query:
SELECT isActive, COUNT(*) as cnt FROM animals WHERE deletedAt IS NULL GROUP BY isActive;
SELECT a.id, a.animalId, a.isActive, a.categoryId, ac.name as categoryName 
FROM animals a 
LEFT JOIN animal_categories ac ON a.categoryId = ac.id 
WHERE a.isActive = 1 AND a.deletedAt IS NULL 
LIMIT 3;

